import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"卢沟桥","description":"","frontmatter":{},"headers":[],"relativePath":"history/lugou-bridge.md","filePath":"history/lugou-bridge.md","lastUpdated":1784712887000}'),o={name:"history/lugou-bridge.md"};function i(n,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="卢沟桥" tabindex="-1">卢沟桥 <a class="header-anchor" href="#卢沟桥" aria-label="Permalink to &quot;卢沟桥&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1599571234909-29ed5d1321d6?w=1200" alt="卢沟桥"></p><blockquote><p>&quot;卢沟晓月，燕京八景；七七事变，民族记忆。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>卢沟桥位于北京市丰台区永定河上，是北京现存最古老的石造联拱桥，也是&quot;燕京八景&quot;之一的&quot;卢沟晓月&quot;所在地。1937年7月7日，卢沟桥事变（七七事变）在此爆发，标志着中国全面抗战的开始。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-17:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">20元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁16号线宛平城站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市丰台区宛平城西门</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>卢沟桥始建于金大定二十九年（1189年），金世宗完颜雍下令修建，金明昌三年（1192年）建成，历时四年。桥名&quot;卢沟&quot;取自永定河古名&quot;卢沟&quot;。</p><h3 id="历代修缮" tabindex="-1">历代修缮 <a class="header-anchor" href="#历代修缮" aria-label="Permalink to &quot;历代修缮&quot;">​</a></h3><ul><li><strong>元代</strong>：马可波罗游历中国，在《马可波罗游记》中称赞卢沟桥为&quot;世界上最好的、独一无二的桥&quot;</li><li><strong>明代</strong>：多次修缮，加固桥身</li><li><strong>清代</strong>：康熙年间重修，乾隆年间再次修缮</li><li><strong>现代</strong>：1982年全面修缮，1997年修复抗日战争时期的弹痕</li></ul><h3 id="七七事变" tabindex="-1">七七事变 <a class="header-anchor" href="#七七事变" aria-label="Permalink to &quot;七七事变&quot;">​</a></h3><p>1937年7月7日夜，日本侵略军在卢沟桥附近进行挑衅性军事演习，借口士兵失踪，要求进入宛平城搜查。遭到拒绝后，日军炮轰宛平城，中国守军奋起抵抗。这就是震惊中外的&quot;卢沟桥事变&quot;（七七事变），标志着中国全面抗战的开始。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="桥身结构" tabindex="-1">桥身结构 <a class="header-anchor" href="#桥身结构" aria-label="Permalink to &quot;桥身结构&quot;">​</a></h3><p>卢沟桥是一座多孔石拱桥，建筑结构独特。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全长</strong></td><td style="text-align:left;">266.5米</td></tr><tr><td style="text-align:left;"><strong>宽度</strong></td><td style="text-align:left;">7.5米</td></tr><tr><td style="text-align:left;"><strong>桥孔</strong></td><td style="text-align:left;">11孔</td></tr><tr><td style="text-align:left;"><strong>桥墩</strong></td><td style="text-align:left;">10座</td></tr><tr><td style="text-align:left;"><strong>桥身</strong></td><td style="text-align:left;">石结构，采用纵联式结构</td></tr></tbody></table><h3 id="石狮" tabindex="-1">石狮 <a class="header-anchor" href="#石狮" aria-label="Permalink to &quot;石狮&quot;">​</a></h3><p>卢沟桥最著名的景观是桥栏上的石狮。</p><h4 id="石狮数量" tabindex="-1">石狮数量 <a class="header-anchor" href="#石狮数量" aria-label="Permalink to &quot;石狮数量&quot;">​</a></h4><ul><li>桥两侧共有望柱281根</li><li>每根望柱上雕有石狮1-5只不等</li><li>石狮总数约500只</li></ul><h4 id="石狮形态" tabindex="-1">石狮形态 <a class="header-anchor" href="#石狮形态" aria-label="Permalink to &quot;石狮形态&quot;">​</a></h4><p>卢沟桥的石狮形态各异，无一雷同。有的大狮抱小狮，有的嬉戏玩耍，有的昂首远眺，形态生动，栩栩如生。</p><h4 id="数狮歌" tabindex="-1">数狮歌 <a class="header-anchor" href="#数狮歌" aria-label="Permalink to &quot;数狮歌&quot;">​</a></h4><p>民间流传着&quot;卢沟桥的石狮数不清&quot;的说法。有&quot;数狮歌&quot;云：</p><blockquote><p>&quot;卢沟桥的石狮，大的抱小的，小的抱更小的，更小的抱最小的，最小的还有更小的。&quot;</p></blockquote><h3 id="碑亭" tabindex="-1">碑亭 <a class="header-anchor" href="#碑亭" aria-label="Permalink to &quot;碑亭&quot;">​</a></h3><p>桥东头有碑亭两座，内立康熙和乾隆皇帝的御碑。</p><ul><li><strong>康熙碑</strong>：立于康熙年间，记述重修卢沟桥经过</li><li><strong>乾隆碑</strong>：立于乾隆年间，记述&quot;卢沟晓月&quot;御笔</li></ul><h2 id="卢沟晓月" tabindex="-1">卢沟晓月 <a class="header-anchor" href="#卢沟晓月" aria-label="Permalink to &quot;卢沟晓月&quot;">​</a></h2><p>&quot;卢沟晓月&quot;是金代燕京八景之一，也是乾隆皇帝钦定的&quot;燕京八景&quot;之一。</p><h3 id="景观特色" tabindex="-1">景观特色 <a class="header-anchor" href="#景观特色" aria-label="Permalink to &quot;景观特色&quot;">​</a></h3><p>每当日出之前，晨霭茫茫，站在卢沟桥上向西远眺，可以欣赏&quot;卢沟晓月&quot;的美景。</p><h3 id="乾隆御笔" tabindex="-1">乾隆御笔 <a class="header-anchor" href="#乾隆御笔" aria-label="Permalink to &quot;乾隆御笔&quot;">​</a></h3><p>乾隆皇帝曾多次游览卢沟桥，题写&quot;卢沟晓月&quot;四字，并立碑刻石。现存碑亭内的&quot;卢沟晓月&quot;碑即为乾隆御笔。</p><h2 id="七七事变与抗战" tabindex="-1">七七事变与抗战 <a class="header-anchor" href="#七七事变与抗战" aria-label="Permalink to &quot;七七事变与抗战&quot;">​</a></h2><h3 id="事变经过" tabindex="-1">事变经过 <a class="header-anchor" href="#事变经过" aria-label="Permalink to &quot;事变经过&quot;">​</a></h3><p>1937年7月7日夜，日军在卢沟桥附近进行军事演习，借口士兵失踪，要求进入宛平城搜查。遭到中国守军拒绝后，日军炮轰宛平城，中国第29军奋起抵抗。</p><h3 id="弹痕遗址" tabindex="-1">弹痕遗址 <a class="header-anchor" href="#弹痕遗址" aria-label="Permalink to &quot;弹痕遗址&quot;">​</a></h3><p>卢沟桥上的石栏、望柱上至今保留着当年的弹痕，是日军侵华的铁证。这些弹痕已被列为文物保护对象，提醒后人铭记历史。</p><h3 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h3><p>七七事变标志着中国全面抗战的开始，是中华民族由衰败走向复兴的转折点。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>卢沟桥游览（约1-2小时）</strong>：</p><p>西门 → 登桥 → 观赏石狮 → 望柱弹痕 → 桥东御碑 → 桥下观赏 → 宛平城</p><p><strong>结合宛平城路线（约半天）</strong>：</p><p>中国人民抗日战争纪念馆 → 宛平城 → 卢沟桥 → 午餐</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">14号线郭庄子站或16号线宛平城站，出站后打车</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">309路、624路等卢沟桥站</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">西四环 → 卢沟桥路</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>仔细观赏</strong>：石狮形态各异，值得细细观赏</li><li><strong>寻找弹痕</strong>：注意寻找当年的弹痕遗址</li><li><strong>结合参观</strong>：建议与宛平城、抗战纪念馆一起参观</li><li><strong>最佳时间</strong>：傍晚时分，可看&quot;卢沟晓月&quot;</li><li><strong>尊重历史</strong>：怀着敬畏之心参观，铭记历史</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">宛平城</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">明代城池，七七事变发生地</td></tr><tr><td style="text-align:left;">中国人民抗日战争纪念馆</td><td style="text-align:center;">宛平城内</td><td style="text-align:left;">全国唯一抗战专题纪念馆</td></tr><tr><td style="text-align:left;">世界公园</td><td style="text-align:center;">约5公里</td><td style="text-align:left;">世界名胜微缩景观</td></tr><tr><td style="text-align:left;">园博园</td><td style="text-align:center;">约10公里</td><td style="text-align:left;">园林博览会会址</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>卢沟桥是中国古代桥梁建筑的杰作，也是抗日战争的重要历史见证。1961年，卢沟桥被列为第一批全国重点文物保护单位。</p><p>卢沟桥的石狮雕刻艺术和桥梁建筑技术，代表了金代石刻艺术和建筑技术的最高水平。</p><hr><p><strong>📍 地址</strong>：北京市丰台区宛平城西门 <strong>📞 电话</strong>：010-83891760</p>',60)])])}const x=e(o,[["render",i]]);export{q as __pageData,x as default};
